  1Ôćĺimport { getLogger } from "@logtape/logtape";
  2Ôćĺimport * as schema from "@rudel/sql-schema";
  3Ôćĺimport { betterAuth } from "better-auth";
  4Ôćĺimport { drizzleAdapter } from "better-auth/adapters/drizzle";
  5Ôćĺimport { bearer, organization } from "better-auth/plugins";
  6Ôćĺimport { fetchGitHubHandle, notifySignup } from "./slack.js";
  7Ôćĺ
  8Ôćĺconst logger = getLogger(["rudel", "api", "auth"]);
  9Ôćĺ
 10Ôćĺexport interface AuthConfig {
 11Ôćĺ	appURL: string;
 12Ôćĺ	secret?: string;
 13Ôćĺ	socialProviders?: Record<string, { clientId: string; clientSecret: string }>;
 14Ôćĺ	trustedOrigins?: string[];
 15Ôćĺ	slackWebhookUrl?: string;
 16Ôćĺ}
 17Ôćĺ
 18Ôćĺ// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
 19Ôćĺexport function createAuth(db: object, config: AuthConfig) {
 20Ôćĺ	const trustedOrigins = config.trustedOrigins ?? [];
 21Ôćĺ	if (!trustedOrigins.includes(config.appURL)) {
 22Ôćĺ		trustedOrigins.push(config.appURL);
 23Ôćĺ	}
 24Ôćĺ
 25Ôćĺ	return betterAuth({
 26Ôćĺ		baseURL: config.appURL,
 27Ôćĺ		secret: config.secret,
 28Ôćĺ		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
 29Ôćĺ			provider: "pg",
 30Ôćĺ			schema,
 31Ôćĺ		}),
 32Ôćĺ		emailAndPassword: {
 33Ôćĺ			enabled: true,
 34Ôćĺ		},
 35Ôćĺ		socialProviders: config.socialProviders,
 36Ôćĺ		plugins: [
 37Ôćĺ			bearer(),
 38Ôćĺ			organization({
 39Ôćĺ				allowUserToCreateOrganization: true,
 40Ôćĺ				creatorRole: "owner",
 41Ôćĺ			}),
 42Ôćĺ		],
 43Ôćĺ		session: {
 44Ôćĺ			expiresIn: 60 * 60 * 24 * 365,
 45Ôćĺ		},
 46Ôćĺ		trustedOrigins,
 47Ôćĺ		databaseHooks: {
 48Ôćĺ			user: {
 49Ôćĺ				create: {
 50Ôćĺ					after: async (user, ctx) => {
 51Ôćĺ						try {
 52Ôćĺ							const adapter = ctx?.context?.adapter;
 53Ôćĺ							if (!adapter) return;
 54Ôćĺ
 55Ôćĺ							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
 56Ôćĺ							const org = await adapter.create({
 57Ôćĺ								model: "organization",
 58Ôćĺ								data: {
 59Ôćĺ									id: user.id,
 60Ôćĺ									name: `${user.name}'s Workspace`,
 61Ôćĺ									slug,
 62Ôćĺ									createdAt: new Date(),
 63Ôćĺ								},
 64Ôćĺ								forceAllowId: true,
 65Ôćĺ							});
 66Ôćĺ
 67Ôćĺ							if (org) {
 68Ôćĺ								await adapter.create({
 69Ôćĺ									model: "member",
 70Ôćĺ									data: {
 71Ôćĺ										organizationId: org.id,
 72Ôćĺ										userId: user.id,
 73Ôćĺ										role: "owner",
 74Ôćĺ										createdAt: new Date(),
 75Ôćĺ									},
 76Ôćĺ								});
 77Ôćĺ							}
 78Ôćĺ
 79Ôćĺ							if (config.slackWebhookUrl) {
 80Ôćĺ								let githubHandle: string | null = null;
 81Ôćĺ								const accounts = (await adapter.findMany({
 82Ôćĺ									model: "account",
 83Ôćĺ									where: [{ field: "userId", value: user.id }],
 84Ôćĺ								})) as Array<{ providerId: string; accountId: string }>;
 85Ôćĺ								const githubAccount = accounts.find(
 86Ôćĺ									(a) => a.providerId === "github",
 87Ôćĺ								);
 88Ôćĺ								if (githubAccount) {
 89Ôćĺ									githubHandle = await fetchGitHubHandle(
 90Ôćĺ										githubAccount.accountId,
 91Ôćĺ									);
 92Ôćĺ								}
 93Ôćĺ								await notifySignup(
 94Ôćĺ									config.slackWebhookUrl,
 95Ôćĺ									{ name: user.name, email: user.email },
 96Ôćĺ									githubHandle,
 97Ôćĺ								);
 98Ôćĺ							}
 99Ôćĺ						} catch (err) {
100Ôćĺ							logger.error(
101Ôćĺ								"Failed to create default organization for user {userId}: {error}",
102Ôćĺ								{ userId: user.id, error: err },
103Ôćĺ							);
104Ôćĺ						}
105Ôćĺ					},
106Ôćĺ				},
107Ôćĺ			},
108Ôćĺ		},
109Ôćĺ	});
110Ôćĺ}
111Ôćĺ
112Ôćĺexport type Auth = ReturnType<typeof createAuth>;
113Ôćĺexport type Session = Auth["$Infer"]["Session"];
