  1Ôćĺimport { join } from "node:path";
  2Ôćĺimport { getLogger, withContext } from "@logtape/logtape";
  3Ôćĺimport { RPCHandler } from "@orpc/server/fetch";
  4Ôćĺimport { createAuth } from "./auth.js";
  5Ôćĺimport { db } from "./db.js";
  6Ôćĺimport { setupLogging } from "./logging.js";
  7Ôćĺimport { router } from "./router.js";
  8Ôćĺ
  9Ôćĺawait setupLogging();
 10Ôćĺ
 11Ôćĺconst logger = getLogger(["rudel", "api", "http"]);
 12Ôćĺ
 13Ôćĺconst socialProviders: Record<
 14Ôćĺ	string,
 15Ôćĺ	{ clientId: string; clientSecret: string }
 16Ôćĺ> = {};
 17Ôćĺif (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 18Ôćĺ	socialProviders.google = {
 19Ôćĺ		clientId: process.env.GOOGLE_CLIENT_ID,
 20Ôćĺ		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 21Ôćĺ	};
 22Ôćĺ}
 23Ôćĺif (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 24Ôćĺ	socialProviders.github = {
 25Ôćĺ		clientId: process.env.GITHUB_CLIENT_ID,
 26Ôćĺ		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 27Ôćĺ	};
 28Ôćĺ}
 29Ôćĺ
 30Ôćĺconst appURL = process.env.APP_URL ?? "http://localhost:4010";
 31Ôćĺconst trustedOrigins = process.env.TRUSTED_ORIGINS
 32Ôćĺ	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 33Ôćĺ	: ["http://localhost:4011"];
 34Ôćĺ
 35Ôćĺconst auth = createAuth(db, {
 36Ôćĺ	appURL,
 37Ôćĺ	secret: process.env.BETTER_AUTH_SECRET,
 38Ôćĺ	socialProviders,
 39Ôćĺ	trustedOrigins,
 40Ôćĺ	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 41Ôćĺ});
 42Ôćĺ
 43Ôćĺconst rpcHandler = new RPCHandler(router);
 44Ôćĺ
 45Ôćĺconst ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 46Ôćĺconst STATIC_DIR = join(
 47Ôćĺ	import.meta.dir,
 48Ôćĺ	"..",
 49Ôćĺ	process.env.STATIC_DIR ?? "public",
 50Ôćĺ);
 51Ôćĺ
 52Ôćĺfunction corsHeaders(origin: string | null): Record<string, string> {
 53Ôćĺ	if (origin !== ALLOWED_ORIGIN) return {};
 54Ôćĺ	return {
 55Ôćĺ		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 56Ôćĺ		"Access-Control-Allow-Credentials": "true",
 57Ôćĺ		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 58Ôćĺ		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 59Ôćĺ	};
 60Ôćĺ}
 61Ôćĺ
 62Ôćĺconst port = process.env.PORT ?? 4010;
 63Ôćĺ
 64Ôćĺconst server = Bun.serve({
 65Ôćĺ	port,
 66Ôćĺ	async fetch(request) {
 67Ôćĺ		const origin = request.headers.get("Origin");
 68Ôćĺ		const cors = corsHeaders(origin);
 69Ôćĺ
 70Ôćĺ		if (request.method === "OPTIONS") {
 71Ôćĺ			return new Response(null, { status: 204, headers: cors });
 72Ôćĺ		}
 73Ôćĺ
 74Ôćĺ		const url = new URL(request.url);
 75Ôćĺ
 76Ôćĺ		// Health check for Fly.io (must be GET-accessible)
 77Ôćĺ		if (url.pathname === "/health") {
 78Ôćĺ			return Response.json({ status: "ok", timestamp: Date.now() });
 79Ôćĺ		}
 80Ôćĺ
 81Ôćĺ		const requestId = crypto.randomUUID();
 82Ôćĺ		const start = performance.now();
 83Ôćĺ
 84Ôćĺ		return withContext(
 85Ôćĺ			{ requestId, method: request.method, path: url.pathname },
 86Ôćĺ			async () => {
 87Ôćĺ				const response = await handleRequest(request, url, cors);
 88Ôćĺ				const duration = Math.round(performance.now() - start);
 89Ôćĺ				logger.info("{method} {path} {status} {duration}ms", {
 90Ôćĺ					method: request.method,
 91Ôćĺ					path: url.pathname,
 92Ôćĺ					status: response.status,
 93Ôćĺ					duration,
 94Ôćĺ				});
 95Ôćĺ				return response;
 96Ôćĺ			},
 97Ôćĺ		);
 98Ôćĺ	},
 99Ôćĺ});
100Ôćĺ
101Ôćĺasync function handleRequest(
102Ôćĺ	request: Request,
103Ôćĺ	url: URL,
104Ôćĺ	cors: Record<string, string>,
105Ôćĺ): Promise<Response> {
106Ôćĺ	if (url.pathname === "/api/cli-token") {
107Ôćĺ		const session = await auth.api.getSession({
108Ôćĺ			headers: request.headers,
109Ôćĺ		});
110Ôćĺ		if (!session) {
111Ôćĺ			return new Response(JSON.stringify({ error: "Not authenticated" }), {
112Ôćĺ				status: 401,
113Ôćĺ				headers: { ...cors, "Content-Type": "application/json" },
114Ôćĺ			});
115Ôćĺ		}
116Ôćĺ		return new Response(JSON.stringify({ token: session.session.token }), {
117Ôćĺ			status: 200,
118Ôćĺ			headers: { ...cors, "Content-Type": "application/json" },
119Ôćĺ		});
120Ôćĺ	}
121Ôćĺ
122Ôćĺ	if (url.pathname.startsWith("/api/auth")) {
123Ôćĺ		const response = await auth.handler(request);
124Ôćĺ		for (const [key, value] of Object.entries(cors)) {
125Ôćĺ			response.headers.set(key, value);
126Ôćĺ		}
127Ôćĺ		return response;
128Ôćĺ	}
129Ôćĺ
130Ôćĺ	const { matched, response } = await rpcHandler.handle(request, {
131Ôćĺ		prefix: "/rpc",
132Ôćĺ		context: await getContext(request),
133Ôćĺ	});
134Ôćĺ
135Ôćĺ	if (matched) {
136Ôćĺ		if (response.status >= 500) {
137Ôćĺ			const body = await response.clone().text();
138Ôćĺ			logger.error("RPC error on {path}: {status} {body}", {
139Ôćĺ				path: url.pathname,
140Ôćĺ				status: response.status,
141Ôćĺ				body,
142Ôćĺ			});
143Ôćĺ		}
144Ôćĺ		for (const [key, value] of Object.entries(cors)) {
145Ôćĺ			response.headers.set(key, value);
146Ôćĺ		}
147Ôćĺ		return response;
148Ôćĺ	}
149Ôćĺ
150Ôćĺ	// Static file serving (production: frontend assets)
151Ôćĺ	const filePath = join(STATIC_DIR, url.pathname);
152Ôćĺ	const file = Bun.file(filePath);
153Ôćĺ	if (await file.exists()) {
154Ôćĺ		return new Response(file);
155Ôćĺ	}
156Ôćĺ
157Ôćĺ	// SPA fallback: serve index.html for non-API routes
158Ôćĺ	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
159Ôćĺ	if (await indexFile.exists()) {
160Ôćĺ		return new Response(indexFile);
161Ôćĺ	}
162Ôćĺ
163Ôćĺ	// Dev mode: redirect to frontend dev server for non-API routes
164Ôćĺ	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
165Ôćĺ	if (ALLOWED_ORIGIN !== appURL) {
166Ôćĺ		return Response.redirect(
167Ôćĺ			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
168Ôćĺ			302,
169Ôćĺ		);
170Ôćĺ	}
171Ôćĺ
172Ôćĺ	return new Response("Not found", { status: 404, headers: cors });
173Ôćĺ}
174Ôćĺ
175Ôćĺasync function getContext(request: Request) {
176Ôćĺ	const session = await auth.api.getSession({
177Ôćĺ		headers: request.headers,
178Ôćĺ	});
179Ôćĺ	return {
180Ôćĺ		user: session?.user ?? null,
181Ôćĺ		session: session?.session ?? null,
182Ôćĺ	};
183Ôćĺ}
184Ôćĺ
185Ôćĺlogger.info("API server listening on http://localhost:{port}", {
186Ôćĺ	port: server.port,
187Ôćĺ});
188Ôćĺ

  1Ôćĺimport { ORPCError } from "@orpc/server";
  2Ôćĺimport { getAdapter } from "@rudel/agent-adapters";
  3Ôćĺimport { member, organization, session } from "@rudel/sql-schema";
  4Ôćĺimport { and, eq } from "drizzle-orm";
  5Ôćĺimport { getClickhouse } from "./clickhouse.js";
  6Ôćĺimport { db } from "./db.js";
  7Ôćĺimport { analyticsRouter } from "./handlers/analytics/index.js";
  8Ôćĺimport { authMiddleware, os } from "./middleware.js";
  9Ôćĺimport {
 10Ôćĺ	deleteOrgSessions,
 11Ôćĺ	getOrgSessionCount,
 12Ôćĺ	migrateOrgSessions,
 13Ôćĺ} from "./services/org-session.service.js";
 14Ôćĺ
 15Ôćĺconst health = os.health.handler(() => {
 16Ôćĺ	return {
 17Ôćĺ		status: "ok" as const,
 18Ôćĺ		timestamp: Date.now(),
 19Ôćĺ	};
 20Ôćĺ});
 21Ôćĺ
 22Ôćĺconst me = os.me.use(authMiddleware).handler(({ context }) => {
 23Ôćĺ	return {
 24Ôćĺ		id: context.user.id,
 25Ôćĺ		email: context.user.email,
 26Ôćĺ		name: context.user.name,
 27Ôćĺ		image: context.user.image ?? null,
 28Ôćĺ		activeOrganizationId:
 29Ôćĺ			((context.session as Record<string, unknown>).activeOrganizationId as
 30Ôćĺ				| string
 31Ôćĺ				| null) ?? null,
 32Ôćĺ	};
 33Ôćĺ});
 34Ôćĺ
 35Ôćĺconst listMyOrganizations = os.listMyOrganizations
 36Ôćĺ	.use(authMiddleware)
 37Ôćĺ	.handler(async ({ context }) => {
 38Ôćĺ		const memberships = await db
 39Ôćĺ			.select({
 40Ôćĺ				id: organization.id,
 41Ôćĺ				name: organization.name,
 42Ôćĺ				slug: organization.slug,
 43Ôćĺ				logo: organization.logo,
 44Ôćĺ			})
 45Ôćĺ			.from(member)
 46Ôćĺ			.innerJoin(organization, eq(member.organizationId, organization.id))
 47Ôćĺ			.where(eq(member.userId, context.user.id));
 48Ôćĺ
 49Ôćĺ		return memberships.map((m) => ({
 50Ôćĺ			id: m.id,
 51Ôćĺ			name: m.name,
 52Ôćĺ			slug: m.slug,
 53Ôćĺ			logo: m.logo ?? null,
 54Ôćĺ		}));
 55Ôćĺ	});
 56Ôćĺ
 57Ôćĺconst ingestSessionHandler = os.ingestSession
 58Ôćĺ	.use(authMiddleware)
 59Ôćĺ	.handler(async ({ input, context }) => {
 60Ôćĺ		const orgId =
 61Ôćĺ			input.organizationId ??
 62Ôćĺ			((context.session as Record<string, unknown>).activeOrganizationId as
 63Ôćĺ				| string
 64Ôćĺ				| null) ??
 65Ôćĺ			context.user.id;
 66Ôćĺ
 67Ôćĺ		if (input.organizationId) {
 68Ôćĺ			const membership = await db
 69Ôćĺ				.select({ id: member.id })
 70Ôćĺ				.from(member)
 71Ôćĺ				.where(
 72Ôćĺ					and(
 73Ôćĺ						eq(member.organizationId, input.organizationId),
 74Ôćĺ						eq(member.userId, context.user.id),
 75Ôćĺ					),
 76Ôćĺ				)
 77Ôćĺ				.limit(1);
 78Ôćĺ
 79Ôćĺ			if (membership.length === 0) {
 80Ôćĺ				throw new ORPCError("FORBIDDEN", {
 81Ôćĺ					message: "Not a member of the specified organization",
 82Ôćĺ				});
 83Ôćĺ			}
 84Ôćĺ		}
 85Ôćĺ
 86Ôćĺ		const adapter = getAdapter(input.source);
 87Ôćĺ		await adapter.ingest(getClickhouse(), input, {
 88Ôćĺ			userId: context.user.id,
 89Ôćĺ			organizationId: orgId,
 90Ôćĺ		});
 91Ôćĺ
 92Ôćĺ		return {
 93Ôćĺ			success: true as const,
 94Ôćĺ			sessionId: input.sessionId,
 95Ôćĺ		};
 96Ôćĺ	});
 97Ôćĺ
 98Ôćĺconst getOrganizationSessionCount = os.getOrganizationSessionCount
 99Ôćĺ	.use(authMiddleware)
100Ôćĺ	.handler(async ({ input, context }) => {
101Ôćĺ		const membership = await db
102Ôćĺ			.select({ id: member.id })
103Ôćĺ			.from(member)
104Ôćĺ			.where(
105Ôćĺ				and(
106Ôćĺ					eq(member.organizationId, input.organizationId),
107Ôćĺ					eq(member.userId, context.user.id),
108Ôćĺ				),
109Ôćĺ			)
110Ôćĺ			.limit(1);
111Ôćĺ
112Ôćĺ		if (membership.length === 0) {
113Ôćĺ			throw new ORPCError("FORBIDDEN", {
114Ôćĺ				message: "Not a member of this organization",
115Ôćĺ			});
116Ôćĺ		}
117Ôćĺ
118Ôćĺ		const count = await getOrgSessionCount(input.organizationId);
119Ôćĺ		return { count };
120Ôćĺ	});
121Ôćĺ
122Ôćĺconst deleteOrganization = os.deleteOrganization
123Ôćĺ	.use(authMiddleware)
124Ôćĺ	.handler(async ({ input, context }) => {
125Ôćĺ		const orgId = input.organizationId;
126Ôćĺ		const userId = context.user.id;
127Ôćĺ		console.log(
128Ôćĺ			`[deleteOrganization] user=${userId} org=${orgId} migrateSessionsTo=${input.migrateSessionsTo ?? "none"}`,
129Ôćĺ		);
130Ôćĺ
131Ôćĺ		// Check user has more than one org
132Ôćĺ		const memberships = await db
133Ôćĺ			.select({ organizationId: member.organizationId })
134Ôćĺ			.from(member)
135Ôćĺ			.where(eq(member.userId, userId));
136Ôćĺ
137Ôćĺ		if (memberships.length <= 1) {
138Ôćĺ			console.log(
139Ôćĺ				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
140Ôćĺ			);
141Ôćĺ			throw new ORPCError("BAD_REQUEST", {
142Ôćĺ				message: "Cannot delete your only organization",
143Ôćĺ			});
144Ôćĺ		}
145Ôćĺ
146Ôćĺ		// Verify user is owner of the target org
147Ôćĺ		const ownership = await db
148Ôćĺ			.select({ id: member.id })
149Ôćĺ			.from(member)
150Ôćĺ			.where(
151Ôćĺ				and(
152Ôćĺ					eq(member.organizationId, orgId),
153Ôćĺ					eq(member.userId, userId),
154Ôćĺ					eq(member.role, "owner"),
155Ôćĺ				),
156Ôćĺ			)
157Ôćĺ			.limit(1);
158Ôćĺ
159Ôćĺ		if (ownership.length === 0) {
160Ôćĺ			console.log(
161Ôćĺ				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
162Ôćĺ			);
163Ôćĺ			throw new ORPCError("FORBIDDEN", {
164Ôćĺ				message: "Only the organization owner can delete it",
165Ôćĺ			});
166Ôćĺ		}
167Ôćĺ
168Ôćĺ		try {
169Ôćĺ			if (input.migrateSessionsTo) {
170Ôćĺ				if (input.migrateSessionsTo === orgId) {
171Ôćĺ					throw new ORPCError("BAD_REQUEST", {
172Ôćĺ						message: "Cannot migrate sessions to the same organization",
173Ôćĺ					});
174Ôćĺ				}
175Ôćĺ
176Ôćĺ				// Verify user is a member of the target org
177Ôćĺ				const targetMembership = await db
178Ôćĺ					.select({ id: member.id })
179Ôćĺ					.from(member)
180Ôćĺ					.where(
181Ôćĺ						and(
182Ôćĺ							eq(member.organizationId, input.migrateSessionsTo),
183Ôćĺ							eq(member.userId, userId),
184Ôćĺ						),
185Ôćĺ					)
186Ôćĺ					.limit(1);
187Ôćĺ
188Ôćĺ				if (targetMembership.length === 0) {
189Ôćĺ					console.log(
190Ôćĺ						`[deleteOrganization] rejected: user=${userId} not member of target org=${input.migrateSessionsTo}`,
191Ôćĺ					);
192Ôćĺ					throw new ORPCError("FORBIDDEN", {
193Ôćĺ						message: "Not a member of the target organization",
194Ôćĺ					});
195Ôćĺ				}
