25Ôćĺ		return {
26Ôćĺ			authenticated: false,
27Ôćĺ			reason: "no_credentials",
28Ôćĺ			message: "Not authenticated. Run `rudel login` first.",
29Ôćĺ		};
30Ôćĺ	}
31Ôćĺ
32Ôćĺ	const client = createApiClient(credentials);
33Ôćĺ	try {
34Ôćĺ		const user = await client.me();
35Ôćĺ		return { authenticated: true, credentials, user };
36Ôćĺ	} catch (error) {
