44Ôćĺ		if (isAuthError) {
45Ôćĺ			clearCredentials();
46Ôćĺ			return {
47Ôćĺ				authenticated: false,
48Ôćĺ				reason: "token_expired",
49Ôćĺ				message:
50Ôćĺ					"Session expired or invalid. Run `rudel login` to re-authenticate.",
51Ôćĺ			};
52Ôćĺ		}
53Ôćĺ
54Ôćĺ		return {
55Ôćĺ			authenticated: false,
56Ôćĺ			reason: "network_error",
57Ôćĺ			message: "Failed to verify authentication. Check your connection.",
