 5Ôćĺ	rmSync,
 6Ôćĺ	writeFileSync,
 7Ôćĺ} from "node:fs";
 8Ôćĺimport { homedir } from "node:os";
 9Ôćĺimport { join } from "node:path";
10Ôćĺ
11Ôćĺexport interface Credentials {
12Ôćĺ	token: string;
13Ôćĺ	apiBaseUrl: string;
14Ôćĺ}
15Ôćĺ
16Ôćĺfunction getConfigDir(): string {
17Ôćĺ	return process.env.RUDEL_CONFIG_DIR ?? join(homedir(), ".rudel");
18Ôćĺ}
