24Ôćĺexport function saveCredentials(token: string, apiBaseUrl: string): void {
25Ôćĺ	const dir = getConfigDir();
26Ôćĺ	if (!existsSync(dir)) {
27Ôćĺ		mkdirSync(dir, { recursive: true, mode: 0o700 });
28Ôćĺ	}
29Ôćĺ	const data: Credentials = { token, apiBaseUrl };
30Ôćĺ	writeFileSync(getCredentialsPath(), JSON.stringify(data, null, 2), {
31Ôćĺ		mode: 0o600,
32Ôćĺ	});
33Ôćĺ}
