  3Ôćĺimport { buildCommand } from "@stricli/core";
  4Ôćĺimport { loadCredentials, saveCredentials } from "../lib/credentials.js";
  5Ôćĺ
  6Ôćĺconst DEFAULT_API_BASE = "https://app.rudel.ai";
  7Ôćĺconst DEFAULT_WEB_URL = "https://app.rudel.ai";
  8Ôćĺconst CALLBACK_TIMEOUT_MS = 120_000;
  9Ôćĺ
 10Ôćĺasync function runLogin(flags: {
 11Ôćĺ	apiBase: string;
 12Ôćĺ	webUrl: string;
 13Ôćĺ	noBrowser: boolean;
 14Ôćĺ}): Promise<void> {
 15Ôćĺ	p.intro("rudel login");
 16Ôćĺ
 17Ôćĺ	const existing = loadCredentials();
 18Ôćĺ	if (existing) {
 19Ôćĺ		p.log.warn("Already logged in.");
 20Ôćĺ		p.outro("Run `rudel logout` first to switch accounts.");
 21Ôćĺ		return;
 22Ôćĺ	}
 23Ôćĺ
 24Ôćĺ	const state = randomBytes(16).toString("hex");
 25Ôćĺ
 26Ôćĺ	let resolveCallback: (token: string) => void;
 27Ôćĺ	let rejectCallback: (error: Error) => void;
 28Ôćĺ	const tokenPromise = new Promise<string>((resolve, reject) => {
 29Ôćĺ		resolveCallback = resolve;
 30Ôćĺ		rejectCallback = reject;
 31Ôćĺ	});
 32Ôćĺ
 33Ôćĺ	const server = Bun.serve({
 34Ôćĺ		port: 0,
 35Ôćĺ		hostname: "127.0.0.1",
 36Ôćĺ		fetch(request) {
 37Ôćĺ			const url = new URL(request.url);
 38Ôćĺ			if (url.pathname !== "/callback") {
 39Ôćĺ				return new Response("Not found", { status: 404 });
 40Ôćĺ			}
 41Ôćĺ
 42Ôćĺ			const receivedToken = url.searchParams.get("token");
 43Ôćĺ			const receivedState = url.searchParams.get("state");
 44Ôćĺ
 45Ôćĺ			if (receivedState !== state) {
 46Ôćĺ				rejectCallback(new Error("State mismatch ÔÇö possible CSRF attack"));
 47Ôćĺ				return new Response(
 48Ôćĺ					"<html><body><h1>Login failed</h1><p>State mismatch. Please try again.</p></body></html>",
 49Ôćĺ					{ headers: { "Content-Type": "text/html" } },
 50Ôćĺ				);
 51Ôćĺ			}
 52Ôćĺ
 53Ôćĺ			if (!receivedToken) {
 54Ôćĺ				rejectCallback(new Error("No token received"));
 55Ôćĺ				return new Response(
 56Ôćĺ					"<html><body><h1>Login failed</h1><p>No token received.</p></body></html>",
 57Ôćĺ					{ headers: { "Content-Type": "text/html" } },
 58Ôćĺ				);
 59Ôćĺ			}
 60Ôćĺ
 61Ôćĺ			resolveCallback(receivedToken);
 62Ôćĺ			return new Response(
 63Ôćĺ				"<html><body><h1>Login successful!</h1><p>You can close this tab and return to the terminal.</p></body></html>",
 64Ôćĺ				{ headers: { "Content-Type": "text/html" } },
 65Ôćĺ			);
 66Ôćĺ		},
 67Ôćĺ	});
 68Ôćĺ
 69Ôćĺ	const callbackUrl = `http://127.0.0.1:${server.port}/callback`;
 70Ôćĺ	const loginUrl = `${flags.webUrl}?cli_callback=${encodeURIComponent(callbackUrl)}&state=${state}`;
 71Ôćĺ
 72Ôćĺ	p.log.info(`If the browser doesn't open, visit:\n${loginUrl}`);
 73Ôćĺ
 74Ôćĺ	// Open browser
 75Ôćĺ	if (!flags.noBrowser) {
 76Ôćĺ		if (process.platform === "win32") {
 77Ôćĺ			Bun.spawn(["cmd", "/c", "start", "", loginUrl], {
 78Ôćĺ				stdout: "ignore",
 79Ôćĺ				stderr: "ignore",
 80Ôćĺ			});
 81Ôćĺ		} else {
 82Ôćĺ			const opener = process.platform === "darwin" ? "open" : "xdg-open";
 83Ôćĺ			Bun.spawn([opener, loginUrl], { stdout: "ignore", stderr: "ignore" });
 84Ôćĺ		}
 85Ôćĺ	}
 86Ôćĺ
 87Ôćĺ	// Wait for callback with timeout
 88Ôćĺ	const timeout = setTimeout(() => {
 89Ôćĺ		rejectCallback(new Error("Login timed out after 120 seconds"));
 90Ôćĺ	}, CALLBACK_TIMEOUT_MS);
 91Ôćĺ
 92Ôćĺ	const spin = p.spinner();
 93Ôćĺ	spin.start("Waiting for browser authentication...");
 94Ôćĺ
 95Ôćĺ	let token: string;
 96Ôćĺ	try {
 97Ôćĺ		token = await tokenPromise;
 98Ôćĺ	} catch (error) {
 99Ôćĺ		clearTimeout(timeout);
100Ôćĺ		server.stop();
101Ôćĺ		spin.stop("Authentication failed");
102Ôćĺ		p.log.error(error instanceof Error ? error.message : String(error));
103Ôćĺ		process.exitCode = 1;
104Ôćĺ		return;
105Ôćĺ	}
106Ôćĺ	clearTimeout(timeout);
107Ôćĺ	server.stop();
108Ôćĺ
109Ôćĺ	spin.message("Validating token...");
110Ôćĺ
111Ôćĺ	// Validate token via /rpc/me
112Ôćĺ	const meResponse = await fetch(`${flags.apiBase}/rpc/me`, {
113Ôćĺ		method: "POST",
114Ôćĺ		headers: {
115Ôćĺ			"Content-Type": "application/json",
116Ôćĺ			Authorization: `Bearer ${token}`,
117Ôćĺ		},
118Ôćĺ		body: JSON.stringify({}),
119Ôćĺ	});
120Ôćĺ
121Ôćĺ	if (!meResponse.ok) {
122Ôćĺ		spin.stop("Token validation failed");
123Ôćĺ		p.log.error("Login failed: token validation failed");
124Ôćĺ		process.exitCode = 1;
125Ôćĺ		return;
126Ôćĺ	}
127Ôćĺ
128Ôćĺ	const body = (await meResponse.json()) as {
129Ôćĺ		json: { id: string; email: string; name: string };
130Ôćĺ	};
131Ôćĺ
132Ôćĺ	saveCredentials(token, flags.apiBase);
133Ôćĺ	spin.stop("Authenticated");
134Ôćĺ	p.log.success(`Logged in as ${body.json.name} (${body.json.email})`);
135Ôćĺ	p.outro("Done!");
136Ôćĺ}
137Ôćĺ
138Ôćĺexport const loginCommand = buildCommand({
139Ôćĺ	loader: async () => ({ default: runLogin }),
140Ôćĺ	parameters: {
141Ôćĺ		flags: {
142Ôćĺ			apiBase: {
143Ôćĺ				kind: "parsed",
144Ôćĺ				parse: String,
145Ôćĺ				brief: "API server base URL",
146Ôćĺ				default: DEFAULT_API_BASE,
147Ôćĺ			},
148Ôćĺ			webUrl: {
149Ôćĺ				kind: "parsed",
150Ôćĺ				parse: String,
151Ôćĺ				brief: "Web app URL for authentication",
152Ôćĺ				default: DEFAULT_WEB_URL,
153Ôćĺ			},
154Ôćĺ			noBrowser: {
155Ôćĺ				kind: "boolean",
156Ôćĺ				brief: "Skip opening the browser automatically",
157Ôćĺ				default: false,
158Ôćĺ			},
159Ôćĺ		},
160Ôćĺ	},
161Ôćĺ	docs: {
162Ôćĺ		brief: "Authenticate with the Rudel API via browser login",
163Ôćĺ	},
164Ôćĺ});
