 23Ôćĺ
 24Ôćĺtype Page = "login" | "signup";
 25Ôćĺ
 26Ôćĺfunction getCliParams(): { cliCallback: string; state: string } | null {
 27Ôćĺ	const params = new URLSearchParams(window.location.search);
 28Ôćĺ	const cliCallback = params.get("cli_callback");
 29Ôćĺ	const state = params.get("state");
 30Ôćĺ	if (!cliCallback || !state) return null;
 31Ôćĺ	try {
 32Ôćĺ		const url = new URL(cliCallback);
 33Ôćĺ		if (url.hostname !== "127.0.0.1") return null;
 34Ôćĺ	} catch {
 35Ôćĺ		return null;
 36Ôćĺ	}
 37Ôćĺ	return { cliCallback, state };
 38Ôćĺ}
 39Ôćĺ
 40Ôćĺfunction getValidRedirect(): string | null {
 41Ôćĺ	const params = new URLSearchParams(window.location.search);
 42Ôćĺ	const redirect = params.get("redirect");
 43Ôćĺ	if (!redirect) return null;
 44Ôćĺ	if (!redirect.startsWith("/") || redirect.startsWith("//")) return null;
 45Ôćĺ	return redirect;
 46Ôćĺ}
 47Ôćĺ
 48Ôćĺfunction App() {
 49Ôćĺ	const { data: session, isPending } = authClient.useSession();
 50Ôćĺ	const [page, setPage] = useState<Page>("login");
 51Ôćĺ	const [cliRedirecting, setCliRedirecting] = useState(false);
 52Ôćĺ	const cliParams = getCliParams();
 53Ôćĺ	const { resolvedTheme } = useTheme();
 54Ôćĺ	const logoSrc =
 55Ôćĺ		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 56Ôćĺ
 57Ôćĺ	useEffect(() => {
 58Ôćĺ		if (!session || !cliParams || cliRedirecting) return;
 59Ôćĺ		setCliRedirecting(true);
 60Ôćĺ
 61Ôćĺ		fetch("/api/cli-token", { credentials: "include" })
 62Ôćĺ			.then((res) => res.json())
 63Ôćĺ			.then((data: { token: string }) => {
 64Ôćĺ				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 65Ôćĺ				window.location.href = redirectUrl;
 66Ôćĺ			});
 67Ôćĺ	}, [session, cliParams, cliRedirecting]);
 68Ôćĺ
 69Ôćĺ	if (isPending) {
 70Ôćĺ		return (
 71Ôćĺ			<div className="flex min-h-screen items-center justify-center">
 72Ôćĺ				<p className="text-muted-foreground">Loading...</p>
 73Ôćĺ			</div>
 74Ôćĺ		);
 75Ôćĺ	}
 76Ôćĺ
 77Ôćĺ	if (cliRedirecting) {
 78Ôćĺ		return (
 79Ôćĺ			<div className="flex min-h-screen items-center justify-center">
 80Ôćĺ				<p className="text-muted-foreground">Completing CLI login...</p>
 81Ôćĺ			</div>
 82Ôćĺ		);
 83Ôćĺ	}
 84Ôćĺ
 85Ôćĺ	if (!session) {
 86Ôćĺ		return (
 87Ôćĺ			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
 88Ôćĺ				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
 89Ôćĺ				{page === "login" ? (
 90Ôćĺ					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 91Ôćĺ				) : (
 92Ôćĺ					<SignupForm onSwitchToLogin={() => setPage("login")} />
 93Ôćĺ				)}
 94Ôćĺ			</div>
 95Ôćĺ		);
 96Ôćĺ	}
 97Ôćĺ
 98Ôćĺ	return (
 99Ôćĺ		<Routes>
100Ôćĺ			<Route
101Ôćĺ				path="/"
102Ôćĺ				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
103Ôćĺ			/>
104Ôćĺ			<Route
105Ôćĺ				path="/invitation/:invitationId"
106Ôćĺ				element={<AcceptInvitationPage />}
107Ôćĺ			/>
108Ôćĺ			<Route path="/dashboard" element={<DashboardLayout />}>
109Ôćĺ				<Route index element={<OverviewPage />} />
110Ôćĺ				<Route path="developers" element={<DevelopersListPage />} />
111Ôćĺ				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
112Ôćĺ				<Route path="projects" element={<ProjectsListPage />} />
113Ôćĺ				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
114Ôćĺ				<Route path="sessions" element={<SessionsListPage />} />
115Ôćĺ				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
116Ôćĺ				<Route path="roi" element={<ROIPage />} />
117Ôćĺ				<Route path="errors" element={<ErrorsPage />} />
118Ôćĺ				<Route path="learnings" element={<LearningsPage />} />
119Ôćĺ				<Route path="profile" element={<ProfilePage />} />
120Ôćĺ				<Route path="invitations" element={<InvitationsPage />} />
121Ôćĺ				<Route path="organization" element={<OrganizationPage />} />
122Ôćĺ				<Route path="organization/new" element={<CreateOrgPage />} />
123Ôćĺ			</Route>
124Ôćĺ			<Route path="*" element={<Navigate to="/dashboard" replace />} />
125Ôćĺ		</Routes>
126Ôćĺ	);
127Ôćĺ}
128Ôćĺ
129Ôćĺexport default App;
