32Ôćĺ			`*Name:* ${user.name}`,
33Ôćĺ			`*Email:* ${user.email}`,
34Ôćĺ		];
35Ôćĺ		if (githubHandle) {
36Ôćĺ			lines.push(`*GitHub:* ${githubHandle}`);
37Ôćĺ		}
